import {
  ChangeDetectionStrategy,
  Component,
  OnInit,
  inject,
  signal,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { ApiService, errorMessage } from '../core/api.service';
import { Account, Contact, Opportunity } from '../core/models';

@Component({
  selector: 'app-account-detail',
  standalone: true,
  imports: [FormsModule, RouterLink],
  templateUrl: './account-detail.component.html',
  styleUrl: './account-detail.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class AccountDetailComponent implements OnInit {
  private readonly route = inject(ActivatedRoute);
  private readonly api = inject(ApiService);
  readonly id = this.route.snapshot.paramMap.get('id') ?? '';

  loading = signal(true);
  saved = signal(false);
  error = signal<string | null>(null);

  // Kept as a single-element array so the approved template's `account()[0]`
  // binding and optimistic `patch()` updates continue to work unchanged.
  account = signal<Account[]>([]);
  contacts = signal<Contact[]>([]);
  opportunities = signal<Opportunity[]>([]);

  async ngOnInit(): Promise<void> {
    this.loading.set(true);
    try {
      const detail = await this.api.accountDetail(this.id);
      this.account.set([detail.account]);
      this.contacts.set(detail.contacts);
      this.opportunities.set(detail.opportunities);
    } catch (err) {
      this.error.set(errorMessage(err, 'Could not load this account.'));
    } finally {
      this.loading.set(false);
    }
  }

  async save(): Promise<void> {
    const current = this.account()[0];
    if (!current) return;
    this.error.set(null);
    try {
      const updated = await this.api.updateAccount({
        id: current.id,
        name: current.name,
        industry: current.industry || undefined,
      });
      // Preserve UI-only fields the backend does not persist.
      this.account.set([{ ...current, ...updated }]);
      this.saved.set(true);
      setTimeout(() => this.saved.set(false), 1800);
    } catch (err) {
      this.error.set(errorMessage(err, 'Could not save changes.'));
    }
  }

  patch<K extends keyof Account>(key: K, value: Account[K]): void {
    this.account.update((list) => {
      const next = [...list];
      if (next[0]) next[0] = { ...next[0], [key]: value };
      return next;
    });
  }
}
